  1→import { Link } from "react-router-dom";
  2→import InstagramCover from "../../assets/images/instagram-icon-cover.png";
  3→import { useState } from "react";
  4→
  5→export default function Hero() {
  6→  const [formValue, setFormValue] = useState({ email: "" });
  7→  const [formError, setFormError] = useState({});
  8→  const [submit, setSubmit] = useState(false);
  9→  const [loading, setLoading] = useState(false);
 10→
 11→  const ResetLocation = () => window.scrollTo(0, 0);
 12→
 13→  const handleSubmit = async (e) => {
 14→    e.preventDefault();
 15→    setLoading(true);
 16→    setFormError(validateForm(formValue));
 17→    if (Object.keys(validateForm(formValue)).length > 0) {
 18→      setLoading(false);
 19→      return null;
 20→    } else {
 21→      setSubmit(true);
 22→      setFormValue({ email: "" });
 23→      setLoading(false);
 24→    }
 25→  };
 26→  const handleValidation = (e) => {
 27→    const { name, value } = e.target;
 28→    setFormValue({ ...formValue, [name]: value });
 29→  };
 30→
 31→  const validateForm = (value) => {
 32→    const errors = {};
 33→    const emailValidation = /^\w+([.-]?\w+)*@\w+([.-]?\w+)*(\.\w{2,3})+$/;
 34→    if (!value.email) {
 35→      errors.email = "Empty email field";
 36→    } else if (!emailValidation.test(value.email)) {
 37→      errors.email = "Invalid email format";
 38→    }
 39→    return errors;
 40→  };
 41→  return (
 42→    <section className="mx-auto max-w-7xl lg:px-8 pt-10 bg-gray-900 sm:pt-16 lg:pt-8 lg:pb-14 lg:overflow-hidden lg:grid lg:grid-cols-2 lg:gap-8">
 43→      <div className="mx-auto max-w-md px-4 sm:max-w-2xl sm:px-6 sm:text-center lg:px-0 lg:text-left flex items-center flex-col gap-3 lg:py-24">
 44→        <h2 className="mt-4 text-5xl tracking-tight font-extrabold text-white sm:mt-5 sm:text-6xl lg:mt-6 xl:text-6xl">
 45→          <span className="block">Edgy</span>
 46→          <span className="block text-[color:var(--primary-font-color)]">
 47→            your Instagram growth secret
 48→          </span>
 49→        </h2>
 50→        <p className="mt-3 text-base text-gray-300 sm:mt-5 sm:text-xl lg:text-lg xl:text-xl">
 51→          Boost your popularity on Instagram with our premium package that will
 52→          skyrocket your profile engagement!
 53→        </p>
 54→        {loading ? (
 55→          <div role="status">
 56→            <svg
 57→              aria-hidden="true"
 58→              className="w-10 h-10 mt-6 text-gray-200 animate-spin dark:text-gray-600 fill-indigo-400"
 59→              viewBox="0 0 100 101"
 60→              fill="none"
 61→              xmlns="http://www.w3.org/2000/svg">
 62→              <path
 63→                d="M100 50.5908C100 78.2051 77.6142 100.591 50 100.591C22.3858 100.591 0 78.2051 0 50.5908C0 22.9766 22.3858 0.59082 50 0.59082C77.6142 0.59082 100 22.9766 100 50.5908ZM9.08144 50.5908C9.08144 73.1895 27.4013 91.5094 50 91.5094C72.5987 91.5094 90.9186 73.1895 90.9186 50.5908C90.9186 27.9921 72.5987 9.67226 50 9.67226C27.4013 9.67226 9.08144 27.9921 9.08144 50.5908Z"
 64→                fill="currentColor"
 65→              />
 66→              <path
 67→                d="M93.9676 39.0409C96.393 38.4038 97.8624 35.9116 97.0079 33.5539C95.2932 28.8227 92.871 24.3692 89.8167 20.348C85.8452 15.1192 80.8826 10.7238 75.2124 7.41289C69.5422 4.10194 63.2754 1.94025 56.7698 1.05124C51.7666 0.367541 46.6976 0.446843 41.7345 1.27873C39.2613 1.69328 37.813 4.19778 38.4501 6.62326C39.0873 9.04874 41.5694 10.4717 44.0505 10.1071C47.8511 9.54855 51.7191 9.52689 55.5402 10.0491C60.8642 10.7766 65.9928 12.5457 70.6331 15.2552C75.2735 17.9648 79.3347 21.5619 82.5849 25.841C84.9175 28.9121 86.7997 32.2913 88.1811 35.8758C89.083 38.2158 91.5421 39.6781 93.9676 39.0409Z"
 68→                fill="currentFill"
 69→              />
 70→            </svg>
 71→            <span className="sr-only">Loading...</span>
 72→          </div>
 73→        ) : submit && Object.keys(formError).length === 0 ? (
 74→          <p className="font-medium text-green-600 sm:text-xl lg:text-lg xl:text-xl">
 75→            Hold tight! Our representative will contact you shortly via email
 76→          </p>
 77→        ) : (
 78→          <form
 79→            onSubmit={handleSubmit}
 80→            className="sm:max-w-xl sm:mx-auto lg:mx-0">
 81→            <section className="sm:flex">
 82→              <section className="min-w-0 flex-1">
 83→                <label htmlFor="email" className="sr-only">
 84→                  Email address
 85→                </label>
 86→                <input
 87→                  id="trial-email"
 88→                  name="email"
 89→                  type="text"
 90→                  value={formValue.email}
 91→                  onChange={handleValidation}
 92→                  placeholder="Enter your email"
 93→                  className="block w-full px-4 py-3 rounded-xl border-2 border-indigo-600 text-white text-base placeholder-gray-500 focus:outline-none focus:ring-2 focus:ring-offset-2 focus:ring-indigo-300 focus:ring-offset-gray-900"
 94→                />
 95→                <span className="text-red-400 mt-6">{formError.email}</span>
 96→              </section>
 97→              <section className="mt-3 sm:mt-0 sm:ml-3">
 98→                <button
 99→                  type="submit"
100→                  className="mt-3 sm:mt-0 sm:ml-3 block w-full py-3 px-4 rounded-md shadow bg-indigo-500 text-white font-medium hover:bg-indigo-600 focus:outline-none focus:ring-2  focus:ring-offset-gray-900">
101→                  Start free trial
102→                </button>
103→              </section>
104→            </section>
105→            <p className="mt-3 text-sm text-gray-300 sm:mt-4">
106→              Start your free 14-day trial, no credit card necessary. By
107→              providing your email, you agree to our
108→              <Link
109→                to="/terms"
110→                className="font-medium text-white"
111→                onClick={ResetLocation}>
112→                {" "}
113→                terms of service
114→              </Link>
115→              .
116→            </p>
117→          </form>
118→        )}
119→      </div>
120→      <img
121→        className="md:w-150 m-auto lg:w-full lg:h-full opacity-60 object-contain "
122→        src={InstagramCover}
123→        alt=""
124→        aria-hidden="true"
125→      />
126→    </section>
127→  );
128→}
